// ── OpenClaw Bridge — Main Logic ──────────────────────────────────
// $json contains the payload sent by the agent + _openclaw metadata
//
// Available:
//   $json.task         — what the agent wants done
//   $json.data         — any structured data the agent passed
//   $json._openclaw    — { agentId, sessionKey, callbackUrl, ts }
//
// This node is where YOU add your automation logic.
// When done, return { result, summary, _openclaw } and the
// next node will POST it back to OpenClaw.

const task      = $json.task || 'unknown';
const data      = $json.data || {};
const _openclaw = $json._openclaw || {};

// ── Add your logic here ───────────────────────────────────────────
// Example: process items, call an API, transform data, etc.
const result = `Task received: ${task}. Data: ${JSON.stringify(data)}`;
const summary = `Completed task: ${task}`;
// ─────────────────────────────────────────────────────────────────

return [{ json: { result, summary, _openclaw } }];
